from __future__ import annotations

from pathlib import Path

from docx import Document
from docx.enum.text import WD_BREAK


ROOT = Path(__file__).resolve().parents[1]
SOURCE = ROOT / "diplom_shumov_work.docx"
OUT = ROOT / "diplom_shumov_hr_docs_final.docx"


def clear_after(doc: Document, keep_count: int) -> None:
    body = doc._body._element
    for p in list(doc.paragraphs)[keep_count:]:
        body.remove(p._element)


def para(doc: Document, text: str = "", style: str | None = None):
    p = doc.add_paragraph(style=style)
    if text:
        p.add_run(text)
    return p


def bullets(doc: Document, items: list[str]) -> None:
    for item in items:
        para(doc, item, "List Paragraph")


def add_section(doc: Document, title: str, body: list[str]) -> None:
    para(doc, title, "Heading 2")
    for block in body:
        para(doc, block)


